/* ===== PAGE LOADER ===== */
function hideLoader() {
  const loader = document.getElementById('loader');
  if(loader && !loader.classList.contains('hidden')) {
    loader.classList.add('hidden');
  }
}
// Hide on DOMContentLoaded (don't wait for CDN resources)
if(document.readyState === 'complete' || document.readyState === 'interactive') {
  setTimeout(hideLoader, 800);
} else {
  document.addEventListener('DOMContentLoaded', () => setTimeout(hideLoader, 1200));
}
// Fallback: always hide after 4 seconds max
setTimeout(hideLoader, 4000);
/* ===== HEADER & NAVIGATION ===== */
try {
const header = document.getElementById('header');
const burger = document.getElementById('burger');
const nav = document.getElementById('nav');
const navLinks = document.querySelectorAll('.nav__link');
const backTop = document.getElementById('backTop');

window.addEventListener('scroll', () => {
  if(header) header.classList.toggle('scrolled', window.scrollY > 50);
  if(backTop) backTop.classList.toggle('show', window.scrollY > 400);
  updateActiveNav();
});

if(burger) burger.addEventListener('click', () => {
  burger.classList.toggle('active');
  nav.classList.toggle('open');
});

navLinks.forEach(link => {
  link.addEventListener('click', () => {
    if(burger) burger.classList.remove('active');
    if(nav) nav.classList.remove('open');
  });
});

if(backTop) backTop.addEventListener('click', () => window.scrollTo({top:0,behavior:'smooth'}));

function updateActiveNav(){
  const sections = document.querySelectorAll('section[id]');
  let current = '';
  sections.forEach(s => {
    if(window.scrollY >= s.offsetTop - 200) current = s.id;
  });
  navLinks.forEach(l => {
    l.classList.toggle('active', l.getAttribute('href') === '#'+current);
  });
}
} catch(e){ console.error('Nav init error:', e); }

/* ===== THEME TOGGLE ===== */
try {
const themeBtn = document.getElementById('themeBtn');
const savedTheme = localStorage.getItem('theme') || 'dark';
document.documentElement.setAttribute('data-theme', savedTheme);
updateThemeIcon();

if(themeBtn) themeBtn.addEventListener('click', () => {
  const isLight = document.documentElement.getAttribute('data-theme') === 'light';
  const newTheme = isLight ? 'dark' : 'light';
  document.documentElement.setAttribute('data-theme', newTheme);
  localStorage.setItem('theme', newTheme);
  updateThemeIcon();
});

function updateThemeIcon(){
  const isLight = document.documentElement.getAttribute('data-theme') === 'light';
  if(themeBtn) themeBtn.innerHTML = isLight ? '<i class="fas fa-sun"></i>' : '<i class="fas fa-moon"></i>';
}
} catch(e){ console.error('Theme init error:', e); }

/* ===== LANGUAGE SWITCHER (dropdown toggle only - translations handled by language-system.js) ===== */
try {
const langBtn = document.getElementById('langBtn');
const langDropdown = document.getElementById('langDropdown');

if(langBtn && langDropdown) langBtn.addEventListener('click', (e) => {
  e.stopPropagation();
  langDropdown.classList.toggle('show');
});

if(langBtn && langDropdown) {
  document.addEventListener('click', () => langDropdown.classList.remove('show'));
}
} catch(e){ console.error('Lang switcher error:', e); }

/* ===== HERO CANVAS PARTICLES ===== */
try {
const canvas = document.getElementById('heroCanvas');
if(canvas){
  const ctx = canvas.getContext('2d');
  let particles = [];
  function resizeCanvas(){
    canvas.width = canvas.parentElement.offsetWidth;
    canvas.height = canvas.parentElement.offsetHeight;
  }
  resizeCanvas();
  window.addEventListener('resize', resizeCanvas);

  class Particle{
    constructor(){this.reset()}
    reset(){
      this.x = Math.random()*canvas.width;
      this.y = Math.random()*canvas.height;
      this.size = Math.random()*2+1;
      this.speedX = (Math.random()-0.5)*0.5;
      this.speedY = (Math.random()-0.5)*0.5;
      this.opacity = Math.random()*0.5+0.2;
    }
    update(){
      this.x += this.speedX;
      this.y += this.speedY;
      if(this.x<0||this.x>canvas.width||this.y<0||this.y>canvas.height) this.reset();
    }
    draw(){
      ctx.beginPath();
      ctx.arc(this.x,this.y,this.size,0,Math.PI*2);
      ctx.fillStyle = 'rgba(37,99,235,'+this.opacity+')';
      ctx.fill();
    }
  }

  for(let i=0;i<60;i++) particles.push(new Particle());

  function animateParticles(){
    ctx.clearRect(0,0,canvas.width,canvas.height);
    particles.forEach(p=>{p.update();p.draw()});
    // Draw lines between close particles
    for(let i=0;i<particles.length;i++){
      for(let j=i+1;j<particles.length;j++){
        const dx=particles[i].x-particles[j].x;
        const dy=particles[i].y-particles[j].y;
        const dist=Math.sqrt(dx*dx+dy*dy);
        if(dist<120){
          ctx.beginPath();
          ctx.moveTo(particles[i].x,particles[i].y);
          ctx.lineTo(particles[j].x,particles[j].y);
          ctx.strokeStyle='rgba(37,99,235,'+(0.15-dist/800)+')';
          ctx.lineWidth=0.5;
          ctx.stroke();
        }
      }
    }
    requestAnimationFrame(animateParticles);
  }
  animateParticles();
}
} catch(e){ console.error('Canvas error:', e); }

/* ===== COUNTER ANIMATION ===== */
function animateCounters(){
  document.querySelectorAll('[data-count]').forEach(el => {
    const target = parseInt(el.dataset.count);
    let current = 0;
    const step = Math.ceil(target/60);
    const timer = setInterval(() => {
      current += step;
      if(current >= target){current = target;clearInterval(timer)}
      el.textContent = current;
    }, 30);
  });
}
let counterDone = false;
const heroStats = document.querySelector('.hero__stats');
if(heroStats){
  const obs = new IntersectionObserver((entries) => {
    if(entries[0].isIntersecting && !counterDone){
      counterDone = true;
      animateCounters();
    }
  },{threshold:0.5});
  obs.observe(heroStats);
}
/* ===== SCROLL REVEAL ===== */
const revealObserver = new IntersectionObserver((entries) => {
  entries.forEach(e => {
    if(e.isIntersecting){
      e.target.classList.add('revealed');
    }
  });
},{threshold:0.1, rootMargin:'0px 0px -50px 0px'});
document.querySelectorAll('.reveal-up,.reveal-left,.reveal-right').forEach(el => revealObserver.observe(el));

/* ===== FAQ ACCORDION ===== */
document.querySelectorAll('.faq-q').forEach(btn => {
  btn.addEventListener('click', () => {
    const item = btn.closest('.faq-item');
    const wasActive = item.classList.contains('active');
    document.querySelectorAll('.faq-item').forEach(i => i.classList.remove('active'));
    if(!wasActive) item.classList.add('active');
  });
});

/* ===== CONTACT FORM ===== */
const contactForm = document.getElementById('contactForm');
if(contactForm){
  contactForm.addEventListener('submit', (e) => {
    e.preventDefault();
    showToast('تم إرسال طلبك بنجاح! سنتواصل معك قريباً.', 'success');
    contactForm.reset();
  });
}

function showToast(msg, type='success'){
  const container = document.getElementById('toastContainer');
  const toast = document.createElement('div');
  toast.className = 'toast toast--'+type;
  toast.innerHTML = '<i class="fas fa-'+(type==='success'?'check-circle':'exclamation-circle')+'"></i><span>'+escapeHtml(msg)+'</span>';
  container.appendChild(toast);
  setTimeout(() => toast.remove(), 4000);
}

function escapeHtml(text) {
  const div = document.createElement('div');
  div.textContent = text;
  return div.innerHTML;
}

