// ===== CHAT PERSISTENCE (localStorage) =====
function saveChatHistory(){
  try{
    const msgs = [];
    chatMessages.querySelectorAll('.chat-msg').forEach(m => {
      const isBot = m.classList.contains('chat-msg--bot');
      const bubble = m.querySelector('.chat-msg__bubble p');
      const time = m.querySelector('.chat-msg__time');
      if(bubble){
        msgs.push({
          type: isBot ? 'bot' : 'user',
          text: bubble.textContent,
          html: bubble.innerHTML,
          time: time ? time.textContent : ''
        });
      }
    });
    localStorage.setItem('me_chat_history', JSON.stringify(msgs.slice(-50)));
    localStorage.setItem('me_chat_count', msgCount.toString());
  } catch(e){}
}

function loadChatHistory(){
  try{
    const saved = localStorage.getItem('me_chat_history');
    const savedCount = localStorage.getItem('me_chat_count');
    if(savedCount) msgCount = parseInt(savedCount) || 0;
    if(saved){
      const msgs = JSON.parse(saved);
      if(msgs.length > 0){
        chatMessages.innerHTML = '';
        msgs.forEach(msg => {
          if(msg.type === 'bot') addBotMessage(msg.text, true);
          else addUserMessage(msg.text, true);
        });
        return true;
      }
    }
  } catch(e){}
  return false;
}

