// ===== SEARCH IN CHAT =====
if(chatSearchBtn){
  chatSearchBtn.addEventListener('click', () => {
    const visible = chatSearchBar.style.display !== 'none';
    chatSearchBar.style.display = visible ? 'none' : 'flex';
    chatSearchBtn.classList.toggle('active', !visible);
    if(!visible) chatSearchInput.focus();
    else clearChatSearch();
  });
}
if(chatSearchClose){
  chatSearchClose.addEventListener('click', () => {
    chatSearchBar.style.display = 'none';
    chatSearchBtn.classList.remove('active');
    clearChatSearch();
  });
}
if(chatSearchInput){
  chatSearchInput.addEventListener('input', () => {
    const query = chatSearchInput.value.trim().toLowerCase();
    if(!query){ clearChatSearch(); return; }
    let count = 0;
    chatMessages.querySelectorAll('.chat-msg__bubble p').forEach(p => {
      const text = p.textContent.toLowerCase();
      if(text.includes(query)){
        const re = new RegExp('(' + query.replace(/[.*+?^${}()|[\]\\]/g,'\\$&') + ')','gi');
        p.innerHTML = escapeHtml(p.textContent).replace(re, '<span class="highlight">$1</span>');
        count++;
      } else {
        p.innerHTML = escapeHtml(p.textContent);
      }
    });
    chatSearchCount.textContent = count > 0 ? count : '0';
  });
}
function clearChatSearch(){
  if(chatSearchInput) chatSearchInput.value = '';
  if(chatSearchCount) chatSearchCount.textContent = '';
  chatMessages.querySelectorAll('.chat-msg__bubble p').forEach(p => {
    if(p.querySelector('.highlight')) p.innerHTML = escapeHtml(p.textContent);
  });
}

// ===== EXPORT CHAT =====
if(chatExport){
  chatExport.addEventListener('click', () => {
    let text = '=== Middle East Law Firm - Chat Export ===\n';
    text += new Date().toLocaleString() + '\n\n';
    chatMessages.querySelectorAll('.chat-msg').forEach(m => {
      const isBot = m.classList.contains('chat-msg--bot');
      const bubble = m.querySelector('.chat-msg__bubble p');
      const time = m.querySelector('.chat-msg__time');
      if(bubble){
        text += (isBot ? '🤖 Bot' : '👤 You') + (time ? ' [' + time.textContent + ']' : '') + ':\n';
        text += bubble.textContent + '\n\n';
      }
    });
    const blob = new Blob([text], {type: 'text/plain;charset=utf-8'});
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'chat-export-' + Date.now() + '.txt';
    a.click();
    URL.revokeObjectURL(url);
    showToast(getChatLang() === 'ar' ? 'تم تصدير المحادثة' : 'Chat exported', 'success');
  });
}

