// ===== SEND MESSAGE =====
function sendMessage(){
  const text = chatInput.value.trim();
  if(!text) return;
  addUserMessage(text);
  chatInput.value = '';
  if(chatCharCount) chatCharCount.textContent = '0/500';
  chatHistory.push({role:'user', text: text});
  if(chatHistory.length > 20) chatHistory.shift();
  msgCount++;
  showTyping();
  const delay = Math.min(600 + text.length * 8, 2000) + Math.random() * 400;
  setTimeout(() => {
    removeTyping();
    const response = getAIResponse(text);
    addBotMessage(response);
    chatHistory.push({role:'bot', text: response});
    if(chatHistory.length > 20) chatHistory.shift();
    msgCount++;
    if(voiceEnabled) speakText(response, getChatLang());
    saveChatHistory();
    updateChatStats();
  }, delay);
}

if(chatSend) chatSend.addEventListener('click', sendMessage);
if(chatInput) chatInput.addEventListener('keypress', (e) => { if(e.key==='Enter') sendMessage(); });

// ===== ADD USER MESSAGE =====
function addUserMessage(text, isRestore){
  const div = document.createElement('div');
  div.className = 'chat-msg chat-msg--user';
  div.innerHTML = '<div class="chat-msg__avatar"><i class="fas fa-user"></i></div><div class="chat-msg__bubble"><p>'+escapeHtml(text)+'</p><span class="chat-msg__time">'+getTimeStr()+'</span></div>';
  chatMessages.appendChild(div);
  chatMessages.scrollTop = chatMessages.scrollHeight;
  if(!isRestore) saveChatHistory();
}

// ===== ADD BOT MESSAGE =====
function addBotMessage(text, isRestore){
  const div = document.createElement('div');
  div.className = 'chat-msg chat-msg--bot';
  const lang = getChatLang();
  const isAr = (lang === 'ar' || lang === 'ku' || lang === 'fa');
  const copyLabel = isAr ? 'نسخ' : (lang==='tr'?'Kopyala':lang==='fr'?'Copier':lang==='de'?'Kopieren':lang==='es'?'Copiar':lang==='ru'?'Копировать':lang==='zh'?'复制':'Copy');
  const speakLabel = isAr ? 'استماع' : (lang==='tr'?'Dinle':lang==='fr'?'Écouter':lang==='de'?'Anhören':lang==='es'?'Escuchar':lang==='ru'?'Слушать':lang==='zh'?'收听':'Listen');
  const likeLabel = isAr ? 'مفيد' : 'Helpful';
  const dislikeLabel = isAr ? 'غير مفيد' : 'Not helpful';

  div.innerHTML = '<div class="chat-msg__avatar"><i class="fas fa-robot"></i></div>'
    + '<div class="chat-msg__bubble">'
    + '<p>' + text.replace(/\n/g,'<br>') + '</p>'
    + '<span class="chat-msg__time">' + getTimeStr() + '</span>'
    + '<div class="chat-msg__actions">'
    + '<button class="chat-msg__speak" title="'+speakLabel+'"><i class="fas fa-volume-up"></i></button>'
    + '<button class="chat-msg__copy" title="'+copyLabel+'"><i class="fas fa-copy"></i></button>'
    + '<button class="chat-msg__react" data-type="like" title="'+likeLabel+'"><i class="fas fa-thumbs-up"></i></button>'
    + '<button class="chat-msg__react" data-type="dislike" title="'+dislikeLabel+'"><i class="fas fa-thumbs-down"></i></button>'
    + '</div></div>';

  // Speak handler
  const speakBtn = div.querySelector('.chat-msg__speak');
  if(speakBtn){
    speakBtn.addEventListener('click', (e) => {
      e.stopPropagation();
      e.preventDefault();
      if(window.speechSynthesis && window.speechSynthesis.speaking){
        window.speechSynthesis.cancel();
        speakBtn.innerHTML = '<i class="fas fa-volume-up"></i>';
        return;
      }
      speakBtn.innerHTML = '<i class="fas fa-volume-off"></i>';
      speakText(text, getChatLang());
      // Reset icon when done
      const checkDone = setInterval(() => {
        if(!window.speechSynthesis || !window.speechSynthesis.speaking){
          clearInterval(checkDone);
          speakBtn.innerHTML = '<i class="fas fa-volume-up"></i>';
        }
      }, 500);
    });
  }

  // Copy handler
  const copyBtn = div.querySelector('.chat-msg__copy');
  if(copyBtn){
    copyBtn.addEventListener('click', (e) => {
      e.stopPropagation();
      e.preventDefault();
      navigator.clipboard.writeText(text).then(() => {
        copyBtn.innerHTML = '<i class="fas fa-check"></i>';
        setTimeout(() => { copyBtn.innerHTML = '<i class="fas fa-copy"></i>'; }, 1500);
      });
    });
  }

  // Reaction handlers
  div.querySelectorAll('.chat-msg__react').forEach(btn => {
    btn.addEventListener('click', (e) => {
      e.stopPropagation();
      e.preventDefault();
      const type = btn.dataset.type;
      const actions = btn.parentElement;
      actions.querySelectorAll('.chat-msg__react').forEach(b => b.classList.remove('liked','disliked'));
      btn.classList.add(type === 'like' ? 'liked' : 'disliked');
    });
  });

  chatMessages.appendChild(div);
  chatMessages.scrollTop = chatMessages.scrollHeight;
  if(!isRestore) saveChatHistory();
}

function showTyping(){
  const div = document.createElement('div');
  div.className = 'chat-msg chat-msg--bot';
  div.id = 'typingIndicator';
  div.innerHTML = '<div class="chat-msg__avatar"><i class="fas fa-robot"></i></div><div class="chat-msg__bubble"><div class="chat-typing"><span></span><span></span><span></span></div></div>';
  chatMessages.appendChild(div);
  chatMessages.scrollTop = chatMessages.scrollHeight;
}

function removeTyping(){
  const typing = document.getElementById('typingIndicator');
  if(typing) typing.remove();
}

