function chatStr(key){ const lang = getChatLang(); return (CHAT_STRINGS[lang] && CHAT_STRINGS[lang][key]) || CHAT_STRINGS['ar'][key] || ''; }

function getCatName(cat){
  const lang = getChatLang();
  if(lang !== 'ar' && CATEGORY_NAMES_EN[cat]) return CATEGORY_NAMES_EN[cat];
  return CATEGORY_NAMES[cat] || cat;
}

function getLawTitle(law){
  const lang = getChatLang();
  if(lang !== 'ar' && lang !== 'ku' && lang !== 'fa' && law.titleEn) return law.titleEn;
  return law.title;
}

function formatLawDetail(law){
  return chatStr('lawDetail')
    .replace('{title}', law.title)
    .replace('{titleEn}', law.titleEn)
    .replace('{number}', law.number)
    .replace('{artCount}', law.articles.length);
}

