/* ===== PWA INSTALL ===== */
let deferredPrompt;
window.addEventListener('beforeinstallprompt', (e) => {
  e.preventDefault();
  deferredPrompt = e;
});

const installPWA = document.getElementById('installPWA');
const installAppBtn = document.getElementById('installAppBtn');

function handleInstall(){
  if(deferredPrompt){
    deferredPrompt.prompt();
    deferredPrompt.userChoice.then((result) => {
      if(result.outcome === 'accepted') showToast('تم تثبيت التطبيق بنجاح!', 'success');
      deferredPrompt = null;
    });
  } else {
    showToast('لتثبيت التطبيق: اضغط على قائمة المتصفح ← "إضافة إلى الشاشة الرئيسية"', 'success');
  }
}

if(installPWA) installPWA.addEventListener('click', (e) => { e.preventDefault(); handleInstall(); });
if(installAppBtn) installAppBtn.addEventListener('click', handleInstall);

/* ===== HERO ROTATING TEXT ===== */
try {
  const rotatingEl = document.getElementById('heroRotating');
  if (rotatingEl) {
    const words = rotatingEl.querySelectorAll('.hero__rotating-word');
    if (words.length > 1) {
      let current = 0;
      setInterval(() => {
        words[current].classList.remove('active');
        words[current].classList.add('exit-up');
        setTimeout(() => { words[current].classList.remove('exit-up'); }, 500);
        current = (current + 1) % words.length;
        words[current].classList.add('active');
      }, 3000);
    }
  }
} catch(e) {}

